/**
 * 配置验证错误类
 */
export class ConfigValidationError extends Error {
  constructor(
    public field: string,
    public value: any,
    public expectedType: string,
    public fixSuggestion?: string
  ) {
    super(`配置项 "${field}" 无效`);
    this.name = 'ConfigValidationError';
  }

  toString(): string {
    let msg = `\n❌ 配置验证失败\n`;
    msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
    msg += `配置项: ${this.field}\n`;
    msg += `当前值: ${JSON.stringify(this.value)}\n`;
    msg += `期望类型: ${this.expectedType}\n`;

    if (this.fixSuggestion) {
      msg += `\n💡 如何修复:\n   ${this.fixSuggestion}\n`;
    }

    msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
    return msg;
  }
}

export class MissingRequiredConfigError extends Error {
  constructor(
    public field: string,
    public envVarName: string
  ) {
    super(`缺少必需的配置: ${field}`);
    this.name = 'MissingRequiredConfigError';
  }

  toString(): string {
    return `\n❌ 缺少必需的环境变量: ${this.envVarName}\n` +
           `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n` +
           `💡 如何修复:\n` +
           `   1. 打开 .env 文件\n` +
           `   2. 添加: ${this.envVarName}=your_value_here\n` +
           `   3. 保存并重启程序\n` +
           `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
