### 3. API 接口设计

```typescript
// 配置验证器 API
interface ConfigValidator<T> {
  // 验证配置
  validate(config: unknown): ValidationResult<T>;

  // 获取默认配置
  getDefaults(): Partial<T>;

  // 生成配置模板
  generateTemplate(): string;

  // 获取类型定义
